import{_ as e,c as a,o as l,a4 as t}from"./chunks/framework.HaEZziQ1.js";const i="/FrontEndLearnNotes/assets/image-20230811163733973.Cw3SMa6y.png",o="/FrontEndLearnNotes/assets/image-20230811164059806.DETCEqP4.png",r="/FrontEndLearnNotes/assets/image-20230811164059806.DETCEqP4.png",s="/FrontEndLearnNotes/assets/image-20230811164213170.DWPoFMwx.png",p="/FrontEndLearnNotes/assets/image-20230811164243270.BxovGpc6.png",n="/FrontEndLearnNotes/assets/image-20230811164648571.BAs5c1yh.png",c="/FrontEndLearnNotes/assets/image-20230811164717301.ZlZRR9hF.png",d="/FrontEndLearnNotes/assets/image-20230811164727661.Cmvs9A-7.png",m="/FrontEndLearnNotes/assets/image-20230811164851799.DGuQVprx.png",h="/FrontEndLearnNotes/assets/image-20230811165507287.wwTPn6ba.png",u="/FrontEndLearnNotes/assets/image-20230811165808130.BJYYYehP.png",_="/FrontEndLearnNotes/assets/image-20230811165903998.BDinp4ZK.png",f="/FrontEndLearnNotes/assets/image-20230811165918734.e80TmOWj.png",g="/FrontEndLearnNotes/assets/image-20230811165944007.C3KNFFXF.png",b="/FrontEndLearnNotes/assets/image-20230811170006101.eyenofoe.png",F="/FrontEndLearnNotes/assets/image-20230811170030076.D3AHg0HB.png",A="/FrontEndLearnNotes/assets/image-20230811170219299.DSi_OU-T.png",v="/FrontEndLearnNotes/assets/image-20230811163400047.hmWiYfEP.png",k="/FrontEndLearnNotes/assets/image-20230811170236820.DSpavPhH.png",V="/FrontEndLearnNotes/assets/image-20230811170219299.DSi_OU-T.png",C="/FrontEndLearnNotes/assets/image-20230811170624935.zniFe3jW.png",T=JSON.parse('{"title":"FFmpeg的安装和目录详解","description":"","frontmatter":{},"headers":[],"relativePath":"Document/基于FFmpeg的使用和开发/2.FFmpeg的安装和目录详解.md","filePath":"Document/基于FFmpeg的使用和开发/2.FFmpeg的安装和目录详解.md","lastUpdated":1709668918000}'),w={name:"Document/基于FFmpeg的使用和开发/2.FFmpeg的安装和目录详解.md"},P=t('<h1 id="ffmpeg的安装和目录详解" tabindex="-1">FFmpeg的安装和目录详解 <a class="header-anchor" href="#ffmpeg的安装和目录详解" aria-label="Permalink to &quot;FFmpeg的安装和目录详解&quot;">​</a></h1><h2 id="一、ffmpeg的安装" tabindex="-1">一、FFmpeg的安装 <a class="header-anchor" href="#一、ffmpeg的安装" aria-label="Permalink to &quot;一、FFmpeg的安装&quot;">​</a></h2><p>下载文档：<a href="https://ffmpeg.org/download.html" target="_blank" rel="noreferrer">Download FFmpeg</a></p><h3 id="mac安装" tabindex="-1">Mac安装 <a class="header-anchor" href="#mac安装" aria-label="Permalink to &quot;Mac安装&quot;">​</a></h3><h3 id="linux安装" tabindex="-1">Linux安装 <a class="header-anchor" href="#linux安装" aria-label="Permalink to &quot;Linux安装&quot;">​</a></h3><h3 id="window安装" tabindex="-1">Window安装 <a class="header-anchor" href="#window安装" aria-label="Permalink to &quot;Window安装&quot;">​</a></h3><p>官网下载（比下面GitHub的下载快一点）：<a href="https://www.gyan.dev/ffmpeg/builds/" target="_blank" rel="noreferrer">Builds：CODEX FFMPEG @ gyan.dev</a></p><p>下载GitHub构建好的版本：<a href="https://github.com/BtbN/FFmpeg-Builds/releases" target="_blank" rel="noreferrer">Releases · BtbN/FFmpeg-Builds (github.com)</a></p><ul><li><p>1.到ffmpeg官方下载已经编译好的Windows <strong>Shared</strong>库；</p></li><li><p>2.解压文件，进入bin目录，能看到单个文件。将这几个执行文件 <code>ffmpeg.exe</code>、 <code>ffplay.exe</code> 、<code>ffprobe.exe</code>拷贝到自己创建的软件目录或者是<code>C:\\Windows</code>目录(不用设置环境变量)，我这里目录是：<code>D:\\SoftWare\\ffmpeg</code></p></li><li><p>3.将相应的.dll动态库拷贝到 <code>C:\\Windows\\SysWOW64</code> 目录；</p><ul><li>注：WOW64 的意思是：Windows-on-Windows 64-bit</li></ul></li><li><p>4.在命令行窗口输入 ffmpeg -version 查看版本，以却确定环境是否搭建成功。</p></li></ul><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">ffmpeg</span><span style="color:#D19A66;"> -version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>5.如果不是放在<code>C:\\Windows</code>，像我一样放在<code>D:\\SoftWare\\ffmpeg</code>，需要设置环境变量来启动命令行模式，把bin目录添加环境变量：<code>D:\\SoftWare\\ffmpeg\\bin</code>。 <ul><li>仅当前windows用户可以使用，如果需要每个用户都能够使用，需要添加到“系统变量”的“Path”条目中</li></ul></li></ul><h2 id="二、ffmpeg-安装目录详解" tabindex="-1">二、FFmpeg 安装目录详解 <a class="header-anchor" href="#二、ffmpeg-安装目录详解" aria-label="Permalink to &quot;二、FFmpeg 安装目录详解&quot;">​</a></h2><p>FFmpeg 解压后后生成4个路径</p><blockquote><p>bin：存放ffmpeg所有的命令工具</p><p>include：存放ffmpeg所有的头文件</p><p>lib：存放ffmpeg生成的动态库或者静态库</p><p>share：存放ffmpeg相关的文档和例子</p></blockquote><h3 id="bin目录" tabindex="-1">bin目录 <a class="header-anchor" href="#bin目录" aria-label="Permalink to &quot;bin目录&quot;">​</a></h3><p>进入bin目录下存在三个命令工具，依次是ffmpeg、ffplay、ffprode</p><blockquote><p>ffmpeg：可以进行推流、音视频的处理</p><p>ffplay：一个播放器，可以进行拉流、播放本地的音视频文件</p><p>ffprobe：用于侦测多媒体文件，例如一些格式以及基本信息</p></blockquote><h3 id="include目录" tabindex="-1">include目录 <a class="header-anchor" href="#include目录" aria-label="Permalink to &quot;include目录&quot;">​</a></h3><p>进入include文件，存放所有的ffmpeg头文件，之后进行ffmpeg二次开发使用头文件时进入此目录下寻找，每一个子目录是一个模块。</p><blockquote><p>libavcodec：编解码</p><p>libavdevice：管理设备</p><p>libavfilter：各种滤镜效果、特效</p><p>libavformat：多媒体格式处理</p><p>libavutil：一些基本的工具</p><p>libswresample：音频重采样</p><p>libswscale：视频缩放等一些处理</p></blockquote><h3 id="lib目录" tabindex="-1">lib目录 <a class="header-anchor" href="#lib目录" aria-label="Permalink to &quot;lib目录&quot;">​</a></h3><p>进入lib文件，存放所有生成的ffmpeg动态库/静态库。</p><p>以libavcodec为例，libavcodec.so.59.0.100是真正的库，另外两个libavcodec.so.59和libavcodec.so是连接符，使用时根据自己的喜好使用。</p><p>如果在移动端使用时也可以生成一个总的静态文件(a文件)。</p><h3 id="share目录" tabindex="-1">share目录 <a class="header-anchor" href="#share目录" aria-label="Permalink to &quot;share目录&quot;">​</a></h3><p>进入share目录下，主要是存在一些ffmpeg文档，例如man文档。</p><p>在Linux下可以使用如下指令查看man手册：</p><blockquote><p>man ls</p></blockquote><h2 id="三、ffmpeg主要组成部分" tabindex="-1">三、ffmpeg主要组成部分 <a class="header-anchor" href="#三、ffmpeg主要组成部分" aria-label="Permalink to &quot;三、ffmpeg主要组成部分&quot;">​</a></h2><h3 id="ffmpeg的整体结构" tabindex="-1">FFMPEG的整体结构 <a class="header-anchor" href="#ffmpeg的整体结构" aria-label="Permalink to &quot;FFMPEG的整体结构&quot;">​</a></h3><p><img src="'+i+`" alt="image-20230811163733973"></p><h3 id="_1-三个主要工具" tabindex="-1">1.三个主要工具 <a class="header-anchor" href="#_1-三个主要工具" aria-label="Permalink to &quot;1.三个主要工具&quot;">​</a></h3><p>ffmpeg：是一个命令行工具，用来对视频文件转换格式，也支持对电视卡实时编码；</p><p>ffsever：是一个HTTP多媒体实时广播流服务器，支持时光平移；</p><p>ffplay：是一个简单的播放器，使用 ffmpeg 库解析和解码，通过SDL显示；</p><h3 id="_2-ffmpeg基本组成模块" tabindex="-1">2.FFmpeg基本组成模块 <a class="header-anchor" href="#_2-ffmpeg基本组成模块" aria-label="Permalink to &quot;2.FFmpeg基本组成模块&quot;">​</a></h3><ul><li>libavformat：用于各种音视频封装格式的生成和解析，包括获取解码所需信息以生成解码上下文结构、读取音视频数据帧等功能，包含demuxers和muxer库；</li><li>libavcodec：音视频各种格式的编解码。</li><li>libavutil：一些公共的工具函数的使用库，包括解码器，工具函数，算数运算，字符操作等。</li><li>libswscale：提供原始视频的比例缩放、色彩映射转换、缩放、图像颜色空间或格式转换的功能。</li><li>libswresample：提供音频混音和重采样，采样格式转换和混合等功能。</li><li>libavfilter：各种音视频滤波器。</li><li>libpostproc：用于后期效果处理，如图像的去块效应等。</li><li>libavdevice：用于硬件的音视频采集、加速和显示，访问捕获设备和回放设备的接口。</li></ul><h4 id="模块相关结构" tabindex="-1">模块相关结构 <a class="header-anchor" href="#模块相关结构" aria-label="Permalink to &quot;模块相关结构&quot;">​</a></h4><ul><li>libavformat有一个非常重要的结构: AVFormatContext；</li></ul><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">它几乎是ffmpeg中的一颗树,</span><span style="color:#98C379;"> 其成员AVStream可以包含0种或多种流,</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#61AFEF;">在AVStream中又可以包含已经打开的编解码器codec,</span><span style="color:#98C379;"> 另外还有AVIOContext成员,</span></span>
<span class="line"><span style="color:#61AFEF;"> 这个成员的作用就是io了,。</span></span>
<span class="line"><span style="color:#61AFEF;">可以重写AVIOContext结构的成员函数read_packet或write_packet等,</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#61AFEF;">来实现从不同介质读取音视频媒体数据(比如从网络、内存或磁盘等</span><span style="color:#ABB2BF;">)，</span></span>
<span class="line"><span style="color:#61AFEF;">关于ffmpeg的io方面,还可以在libavformat中自己实现一个</span><span style="color:#98C379;"> PROTOCOL组件来实现同样的功能,</span><span style="color:#ABB2BF;"> </span></span>
<span class="line"><span style="color:#61AFEF;">方法也很简单,</span><span style="color:#98C379;"> 只要实现URLProtocol结构然后取个名字在allformats.c中使用REGISTER_PROTOCOL</span></span>
<span class="line"><span style="color:#61AFEF;">添加一行注册自己的协议就行,</span><span style="color:#98C379;"> 其它DEMUXER和MUXDEMUX方法也是相似的。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li><p>libavformat也提供了AVOutputFormat、AVInputFormat、URLProtocol等。</p></li><li><p>libavcodec也有一个非常重要的结构: AVCodecContext；</p></li></ul><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">它包含了当前媒体信息的几乎所有参数(什么宽高,</span><span style="color:#98C379;"> 运行估计,</span><span style="color:#98C379;"> 码率控制...</span><span style="color:#ABB2BF;">), 以及编解码指针(</span><span style="color:#61AFEF;">AVCodec</span><span style="color:#ABB2BF;">),</span></span>
<span class="line"><span style="color:#61AFEF;">甚至还可以设置硬件加速相关(如DXVA,</span><span style="color:#98C379;"> linux下的</span><span style="color:#98C379;"> VAAPI</span><span style="color:#ABB2BF;">). </span></span>
<span class="line"><span style="color:#61AFEF;">其中最重要的属AVCodec,</span><span style="color:#98C379;"> 它是直接指向编解码器实现,</span></span>
<span class="line"><span style="color:#61AFEF;">如果你想自己实现一个编解码添加到libavcodec中,</span><span style="color:#98C379;"> 那么也是非常方便的。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>libavcodec也提供了AVHWAccel、AVCodec、AVCodecParser、AVBitStreamFilter等。</li></ul><h4 id="_1-封装格式" tabindex="-1">1 封装格式 <a class="header-anchor" href="#_1-封装格式" aria-label="Permalink to &quot;1 封装格式&quot;">​</a></h4><p>AVFormatContext - 描述了媒体文件的构成及基本信息，是统领全局的基本结构体，贯穿程序始终，很多函数都要用它作为参数，格式转换过程中实现输入和输出功能、保存相关数据的主要结构，描述了一个媒体文件或媒体流的构成和基本信息；</p><ul><li>nb_streams/streams ：AVStream结构指针数组, 包含了所有内嵌媒体流的描述，其内部有 AVInputFormat + AVOutputFormat 结构体，来表示输入输出的文件格式</li><li>avformat_open_input：创建并初始化部分值，但其他一些值(如 mux_rate、key 等)需要手工设置初始值，否则可能出现异常</li><li>avformat_alloc_output_context2：根据文件的输出格式、扩展名或文件名等分配合适的 AVFormatContext 结构</li></ul><p>AVInputFormat - 解复用器对象，每种作为输入的封装格式(例如FLV、MP4、TS等)对应一个该结构体，如libavformat/flvdec.c的ff_flv_demuxer；</p><p>AVOutputFormat - 复用器对象，每种作为输出的封装格式（例如FLV, MP4、TS等）对应一个该结构体，如libavformat/flvenc.c的ff_flv_muxer；</p><p>AVStream - 用于描述一个媒体流，其大部分信息可通过 avformat_open_input 根据文件头信息确定，其他信息可通过 avformat_find_stream_info 获取，典型的有 视频流、中英文音频流、中英文字幕流(Subtitle)，可通过 av_new_stream、avformat_new_stream 等创建。</p><ul><li>index：在AVFormatContext中流的索引，其值自动生成(AVFormatContext::streams[index])</li><li>nb_frames：流内的帧数目</li><li>time_base：流的时间基准，是一个实数，该流中媒体数据的pts和dts都将以这个时间基准为粒度。通常，使用av_rescale/av_rescale_q可以实现不同时间基准的转换</li><li>avformat_find_stream_info：获取必要的编解码器参数(如 AVMediaType、CodecID )，设置到 AVFormatContext::streams[i]::codec 中</li><li>av_read_frame：从多媒体文件或多媒体流中读取媒体数据，获取的数据由 AVPacket 来存放</li><li>av_seek_frame：改变媒体文件的读写指针来实现对媒体文件的随机访问，通常支持基于时间、文件偏移、帧号(AVSEEK_FLAG_FRAME)的随机访问方式</li></ul><h4 id="_2-编解码" tabindex="-1">2 编解码 <a class="header-anchor" href="#_2-编解码" aria-label="Permalink to &quot;2 编解码&quot;">​</a></h4><p>AVCodecContext - 描述编解码器上下文的数据结构，包含了众多编解码器需要的参数信息，保存AVCodec指针和与codec相关的数据，包含了流中所使用的关于编解码器的所有信息；</p><ul><li>codec_name[32]、codec_type(AVMediaType)、codec_id(CodecID)、codec_tag：编解码器的名字、类型(音频/视频/字幕等)、ID(H264/MPEG4等)、FOURC等信息</li><li>hight/width,coded_width/coded_height： Video的高宽</li><li>sample_fmt：音频的原始采样格式, 是 SampleFormat 枚举</li><li>time_base：采用分数(den/num)保存了帧率的信息</li></ul><p>AVCodec - 编解码器对象，编解码器，采用链表维护，每一个都有其对应的名字、类型、CodecID和对数据进行处理的编解码函数指针，每种编解码格式(例如H.264、AAC等）对应一个该结构体。每个AVCodecContext中含有一个AVCodec；</p><p>AVCodecParameters - 编解码参数，每个AVStream中都含有一个AVCodecParameters，用来存放当前流的编解码参数。</p><ul><li>avcodec_find_decoder/avcodec_find_encoder ：根据给定的codec id或解码器名称从系统中搜寻并返回一个AVCodec结构的指针</li><li>avcodec_alloc_context3：根据 AVCodec 分配合适的 AVCodecContext</li><li>avcodec_open/avcodec_open2/avcodec_close ：根据给定的 AVCodec 打开对应的Codec，并初始化 AVCodecContext/ 关闭Codec</li><li>avcodec_alloc_frame：分配编解码需要的 AVFrame 结构</li><li>avcodec_decode_video/avcodec_decode_video2 ：解码一个视频帧，输入数据在AVPacket结构中，输出数据在AVFrame结构中</li><li>avcodec_decode_audio4：解码一个音频帧。输入数据在AVPacket结构中，输出数据在AVFrame结构中</li><li>avcodec_encode_video/avcodec_encode_video2 ：编码一个视频帧，输入数据在AVFrame结构中，输出数据在AVPacket结构中</li></ul><h4 id="_4-3-网络协议" tabindex="-1">4.3 网络协议 <a class="header-anchor" href="#_4-3-网络协议" aria-label="Permalink to &quot;4.3 网络协议&quot;">​</a></h4><p>AVIOContext - 管理输入输出数据的结构体；</p><p>URLProtocol - 描述了音视频数据传输所使用的协议，每种传输协议(例如HTTP、RTMP)等，都会对应一个URLProtocol结构；</p><p>URLContext - 封装了协议对象及协议操作对象。</p><h4 id="_4-4-数据存放" tabindex="-1">4.4 数据存放 <a class="header-anchor" href="#_4-4-数据存放" aria-label="Permalink to &quot;4.4 数据存放&quot;">​</a></h4><p>AVPacket - 存放编码后、解码前的压缩数据，即ES数据， 暂存解码之前的媒体数据（一个音/视频帧、一个字幕包等）及附加信息（解码时间戳、显示时间戳、时长等)，主要用于建立缓冲区并装载数据；</p><ul><li>data/size/pos： 数据缓冲区指针、长度和媒体流中的字节偏移量</li><li>flags：标志域的组合，1(AV_PKT_FLAG_KEY)表示该数据是一个关键帧, 2(AV_PKT_FLAG_CORRUPT)表示该数据已经损坏</li><li>destruct：释放数据缓冲区的函数指针，其值可为 [av_destruct_packet]/av_destruct_packet_nofree, 会被 av_free_packet 调用。</li></ul><p>AVFrame - 存放编码前、解码后的原始数据，如YUV格式的视频数据或PCM格式的音频数据等；</p><ul><li>data/linesize：FFMpeg内部以平面的方式存储原始图像数据，即将图像像素分为多个平面（R/G/B或Y/U/V）数组</li><li>data数组：其中的指针指向各个像素平面的起始位置，编码时需要用户设置数据</li><li>linesize数组 ：存放各个存贮各个平面的缓冲区的行宽，编码时需要用户设置数据</li><li>key_frame：该图像是否是关键帧，由 libavcodec 设置</li><li>pict_type：该图像的编码类型：Intra(1)/Predicted(2)/Bi-dir(3) 等，默认值是 NONE(0)，其值由libavcodec设置</li><li>pts：呈现时间，编码时由用户设置</li><li>quality：从1(最好)到FF_LAMBDA_MAX(256*128-1,最差)，编码时用户设置，默认值是0</li><li>nterlaced_frame：表明是否是隔行扫描的,编码时用户指定，默认0</li></ul><h3 id="组成部分中-需要熟悉基础概念有" tabindex="-1">组成部分中，需要熟悉基础概念有 <a class="header-anchor" href="#组成部分中-需要熟悉基础概念有" aria-label="Permalink to &quot;组成部分中，需要熟悉基础概念有&quot;">​</a></h3><p>容器(Container)</p><ul><li>容器就是一种文件格式，比如flv，mkv等。包含下面5种流以及文件头信息。</li></ul><p>流(Stream)</p><ul><li>是一种视频数据信息的传输方式，5种流：音频，视频，字幕，附件，数据。</li></ul><p>帧(Frame)</p><ul><li>帧代表一幅静止的图像，分为I帧，P帧，B帧。</li></ul><p>编解码器(Codec)</p><ul><li>是对视频进行压缩或者解压缩，CODEC =COde （编码） +DECode（解码）</li></ul><p>复用/解复用(mux/demux)</p><ul><li>把不同的流按照某种容器的规则放入容器，这种行为叫做复用（mux）</li><li>把不同的流从某种容器中解析出来，这种行为叫做解复用(demux)</li></ul><h4 id="ffmpeg有8个常用库" tabindex="-1">FFMPEG有8个常用库 <a class="header-anchor" href="#ffmpeg有8个常用库" aria-label="Permalink to &quot;FFMPEG有8个常用库&quot;">​</a></h4><ul><li>AVUtil：核心工具库，下面的许多其他模块都会依赖该库做一些基本的音视频处理操作。</li><li>AVFormat：文件格式和协议库，该模块是最重要的模块之一，封装了Protocol层和Demuxer、Muxer层，使得协议和格式对于开发者来说是透明的。</li><li>AVCodec：编解码库，封装了Codec层，但是有一些Codec是具备自己的License的，FFmpeg是不会默认添加像libx264、FDK-AAC等库的，但是FFmpeg就像一个平台一样，可以将其他的第三方的Codec以插件的方式添加进来，然后为开发者提供统一的接口。</li><li>AVFilter：音视频滤镜库，该模块提供了包括音频特效和视频特效的处理，在使用FFmpeg的API进行编解码的过程中，直接使用该模块为音视频数据做特效处理是非常方便同时也非常高效的一种方式。</li><li>AVDevice：输入输出设备库，比如，需要编译出播放声音或者视频的工具ffplay，就需要确保该模块是打开的，同时也需要SDL的预先编译，因为该设备模块播放声音与播放视频使用的都是SDL库。</li><li>SwrRessample：该模块可用于音频重采样，可以对数字音频进行声道数、数据格式、采样率等多种基本信息的转换。</li><li>SWScale：该模块是将图像进行格式转换的模块，比如，可以将YUV的数据转换为RGB的数据，缩放尺寸由1280<em>720变为800</em>480。</li><li>PostProc：该模块可用于进行后期处理，当我们使用AVFilter的时候需要打开该模块的开关，因为Filter中会使用到该模块的一些基础函数。</li></ul><h3 id="查看帮助" tabindex="-1">查看帮助 <a class="header-anchor" href="#查看帮助" aria-label="Permalink to &quot;查看帮助&quot;">​</a></h3><ul><li>可用的bit流 ：ffmpeg –bsfs</li><li>可用的编解码器：ffmpeg –codecs</li><li>可用的解码器：ffmpeg –decoders</li><li>可用的编码器：ffmpeg –encoders</li><li>可用的过滤器：ffmpeg –filters</li><li>可用的视频格式：ffmpeg –formats</li><li>可用的声道布局：ffmpeg –layouts</li><li>可用的license：ffmpeg –L</li><li>可用的像素格式：ffmpeg –pix_fmts</li><li>可用的协议：ffmpeg -protocals</li></ul><h3 id="ffmpeg函数" tabindex="-1">FFmpeg函数 <a class="header-anchor" href="#ffmpeg函数" aria-label="Permalink to &quot;FFmpeg函数&quot;">​</a></h3><ul><li><p>数据包/数据帧(AVPacket/AVFrame)</p></li><li><p>av_packet_alloc/av_frame_alloc(分配数据包/分配数据帧)</p></li><li><p>av_packet_free/av_frame_alloc(释放数据包内存/释放数据帧内存)</p></li><li><p>av_register_all()：注册所有组件,4.0已经弃用</p></li><li><p>avdevice_register_all()对设备进行注册，比如V4L2等。</p></li><li><p>avformat_network_init();初始化网络库以及网络加密协议相关的库（比如openssl）</p></li><li><p>avformat_alloc_context();负责申请一个AVFormatContext结构的内存,并进行简单初始化</p></li><li><p>avformat_free_context();释放该结构里的所有东西以及该结构本身</p></li><li><p>avformat_close_input();关闭解复用器。关闭后就不再需要使用avformat_free_context 进行释放。</p></li><li><p>avformat_open_input();打开输入视频文件</p></li><li><p>avformat_find_stream_info()：获取视频文件信息</p></li><li><p>av_read_frame(); 读取音视频包</p></li><li><p>avformat_seek_file(); 定位文件</p></li><li><p>av_seek_frame():定位文件</p></li></ul><p>图例</p><p><img src="`+o+'" alt="image-20230811164059806"></p><ul><li>avcodec_alloc_context3():分配解码器上下文</li><li>avcodec_find_decoder()：根据ID查找解码器</li><li>avcodec_find_decoder_by_name():根据解码器名字</li><li>avcodec_open2()：打开编解码器</li><li>avcodec_decode_video2()：解码一帧视频数据</li><li>avcodec_decode_audio4()：解码一帧音频数据</li><li>avcodec_send_packet():发送编码数据包</li><li>avcodec_receive_frame():接收解码后数据</li><li>avcodec_free_context():释放解码器上下文，包含了</li><li>avcodec_close()avcodec_close():关闭解码器</li></ul><p>解码函数</p><p><img src="'+r+'" alt="image-20230811164205618"></p><p>2</p><p><img src="'+s+'" alt="image-20230811164213170"></p><p>封装媒体容器</p><ul><li>注册模块-&gt;打开输出上下文-&gt;增加流-&gt;写文件头-&gt;循环写入数据包-&gt;写入文件结尾数据</li></ul><p>解封装</p><ul><li>注册模块-&gt;打开输入上下文-&gt;查找音视频流信息-&gt;循环读取视频包-&gt;关闭输入上下文</li></ul><p>解码和编码</p><ul><li>注册模块-&gt;查找解码器-&gt;分配解码器上下文-&gt;打开解码器-&gt;发送数据包-&gt;循环读取完，解码后的数据帧-&gt;释放解码器上下文</li><li>编码跟解码类似</li></ul><p>滤镜处理流程</p><ul><li>流程</li></ul><h3 id="组件注册方式" tabindex="-1">组件注册方式 <a class="header-anchor" href="#组件注册方式" aria-label="Permalink to &quot;组件注册方式&quot;">​</a></h3><p>我们使用ffmpeg，首先要执行av_register_all，把全局的解码器、编码器等结构体注册到各自全局的对象链表里，以便后面查找调用。</p><p>AAC、H264</p><p><img src="'+p+'" alt="image-20230811164243270"></p><p>FFMPEG内部去做，不需要用户调用API去注册。以codec编解码器为例：</p><ul><li>1.在configure的时候生成要注册的组件<code>./configure:7203:print_enabled_components libavcodec/codec_list.c AVCodec codec_list $CODEC_LIST</code> 这里会生成一个 <code>codec_list.c</code> 文件，里面只有 <code>static const AVCodec * const codec_list[]</code> 数组。</li><li>2.在 <code>libavcodec/allcodecs.c</code> 将 <code>static const AVCodec * const codec_list[]</code> 的编解码器用链表的方式组织起来。</li></ul><p>FFmpeg内部去做，不需要用户调用API去注册。</p><p>对于demuxer/muxer（解复用器，也称容器）则对应</p><ul><li>1.<code>libavformat/muxer_list.c libavformat/demuxer_list.c</code> 这两个文件也是在 <code>configure</code> 的时候生成，也就是说直接下载源码是没有这两个文件的。</li><li>2.在 <code>libavformat/allformats.c</code> 将<code>demuxer_list[]</code> 和 <code>muexr_list[]</code> 以链表的方式组织。</li></ul><p>其他组件也是类似的方式。</p><h3 id="ffmpeg数据结构简介" tabindex="-1">FFmpeg数据结构简介 <a class="header-anchor" href="#ffmpeg数据结构简介" aria-label="Permalink to &quot;FFmpeg数据结构简介&quot;">​</a></h3><p>AVFormatContext：封装格式上下文结构体，也是统领全局的结构体，保存了视频文件封装格式相关信息。</p><p>AVInputFormat demuxer：每种封装格式（例如FLV, MKV, MP4, AVI）对应一个该结构体。</p><p>AVOutputFormat muxerAVStream：视频文件中每个视频（音频）流对应一个该结构体。</p><p>AVCodecContext：编解码器上下文结构体，保存了视频（音频）编解码相关信息</p><p>AVCodec：每种视频（音频）编解码器(例如H.264解码器)对应一个该结构体。</p><p>AVPacket：存储一帧压缩编码数据。</p><p>AVFrame：存储一帧解码后像素（采样）数据。</p><p>AVFormatContext和AVInputFormat之间的关系</p><p>AVFormatContext API调用</p><p>AVInputFormat 主要是FFMPEG内部调用</p><p><img src="'+n+'" alt="image-20230811164648571"></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">int</span><span style="color:#98C379;"> avformat_open_input</span><span style="color:#ABB2BF;">(</span><span style="color:#61AFEF;">AVFormatContext</span><span style="color:#E5C07B;"> **</span><span style="color:#98C379;">ps,</span><span style="color:#98C379;"> const</span><span style="color:#98C379;"> char</span><span style="color:#E5C07B;"> *</span><span style="color:#98C379;">filename,</span><span style="color:#98C379;"> AVInputFormat</span><span style="color:#E5C07B;"> *</span><span style="color:#98C379;">fmt,</span><span style="color:#98C379;"> AVDictionary</span><span style="color:#E5C07B;"> **</span><span style="color:#98C379;">options</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AVCodecContext和AVCodec之间的关系</p><p><img src="'+c+'" alt="image-20230811164717301"></p><p>AVFormatContext, AVStream和AVCodecContext之间的关系</p><p><img src="'+d+'" alt="image-20230811164727661"></p><p>区分不同的码流</p><p>AVMEDIA_TYPE_VIDEO视频流</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">video_index</span><span style="color:#98C379;"> =</span><span style="color:#98C379;"> av_find_best_stream</span><span style="color:#ABB2BF;">(</span><span style="color:#61AFEF;">ic,</span><span style="color:#98C379;"> AVMEDIA_TYPE_VIDEO,-1,-1,</span><span style="color:#98C379;"> NULL,</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AVMEDIA_TYPE_AUDIO音频流</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">audio_index</span><span style="color:#98C379;"> =</span><span style="color:#98C379;"> av_find_best_stream</span><span style="color:#ABB2BF;">(</span><span style="color:#61AFEF;">ic,</span><span style="color:#98C379;"> AVMEDIA_TYPE_AUDIO,-1,-1,</span><span style="color:#98C379;"> NULL,</span><span style="color:#D19A66;"> 0</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>AVPacket和AVFrame之间的关系</p><p><img src="'+m+'" alt="image-20230811164851799"></p><p>AVFormatContext</p><ul><li>iformat：输入媒体的AVInputFormat，比如指向AVInputFormat ff_flv_demuxer</li><li>nb_streams：输入媒体的AVStream 个数</li><li>streams：输入媒体的AVStream []数组</li><li>duration：输入媒体的时长（以微秒为单位），计算方式可以参考av_dump_format()函数。</li><li>bit_rate：输入媒体的码率</li></ul><p>AVInputFormat -&gt;解复用器 -&gt; 拆解文件时用</p><ul><li>name：封装格式名称</li><li>extensions：封装格式的扩展名</li><li>id：封装格式ID一些封装格式处理的接口函数,比如read_packet()</li></ul><p>AVOutputFormat 复用器 合成文件时用</p><p>AVStream</p><ul><li>index：标识该视频/音频流</li><li>time_base：该流的时基，PTS*time_base=真正的时间（秒）</li><li>avg_frame_rate： 该流的帧率</li><li>duration：该视频/音频流长度</li><li>codecpar：编解码器参数属性</li></ul><p>AVCodecParameters</p><ul><li>codec_type：媒体类型AVMEDIA_TYPE_VIDEO/ AVMEDIA_TYPE_AUDIO等</li><li>codec_id：编解码器类型， AV_CODEC_ID_H264/ AV_CODEC_ID_AAC等。</li></ul><p>AVCodecContext</p><ul><li>codec：编解码器的AVCodec，比如指向AVCodec ff_aac_latm_decoder</li><li>width, height：图像的宽高（只针对视频）</li><li>pix_fmt：像素格式（只针对视频）</li><li>sample_rate：采样率（只针对音频）</li><li>channels：声道数（只针对音频）</li><li>sample_fmt：采样格式（只针对音频）</li></ul><p>AVCodec</p><ul><li>name：编解码器名称 (多家H264解码厂商， a-h264, b-h264)</li><li>type：编解码器类型</li><li>id：编解码器ID H264一些编解码的接口函数，比如int (*decode)()</li></ul><p>AVPacket</p><ul><li>pts：显示时间戳</li><li>dts：解码时间戳</li><li>data：压缩编码数据</li><li>size：压缩编码数据大小</li><li>pos:数据的偏移地址</li><li>stream_index：所属的AVStream</li></ul><p>AVFrame</p><ul><li>data[]：解码后的图像像素数据（音频采样数据）</li><li>linesize[]：对视频来说是图像中一行像素的大小；对音频来说是整个音频帧的大小</li><li>width, height：图像的宽高（只针对视频）</li><li>key_frame：是否为关键帧（只针对视频） 。</li><li>pict_type：帧类型（只针对视频） 。例如I， P， B</li><li>sample_rate：音频采样率（只针对音频）</li><li>nb_samples：音频每通道采样数（只针对音频）</li><li>pts：显示时间戳</li></ul><h3 id="sdl简介" tabindex="-1">SDL简介 <a class="header-anchor" href="#sdl简介" aria-label="Permalink to &quot;SDL简介&quot;">​</a></h3><p>作用：SDL(Simple DirectMedia Layer)库的作用主要是封装了复杂的视音频底层交互工作， 简化了视音频处理的难度。</p><p>本次课程我们重点不在SDL，只因为涉及到一些函数的调用，所以只稍微做一个简介</p><p>SDL结构如下所示。可以看出它实际上还是调用了DirectX等底层的API完成了和硬件的交互</p><p><img src="'+h+'" alt="image-20230811165507287"></p><h4 id="sdl视频显示函数简介" tabindex="-1">SDL视频显示函数简介 <a class="header-anchor" href="#sdl视频显示函数简介" aria-label="Permalink to &quot;SDL视频显示函数简介&quot;">​</a></h4><ul><li>SDL_Init()：初始化SDL系统</li><li>SDL_CreateWindow()：创建窗口</li><li>SDL_WindowSDL_CreateRenderer()：创建渲染器</li><li>SDL_RendererSDL_CreateTexture()：创建纹理</li><li>SDL_TextureSDL_UpdateTexture()：设置纹理的数据</li><li>SDL_RenderCopy()：将纹理的数据拷贝给渲染器</li><li>SDL_RenderPresent()：显示</li><li>SDL_Delay()：工具函数，用于延时。</li><li>SDL_Quit()：退出SDL系统</li></ul><h4 id="sdl多线程" tabindex="-1">SDL多线程 <a class="header-anchor" href="#sdl多线程" aria-label="Permalink to &quot;SDL多线程&quot;">​</a></h4><h5 id="sdl多线程函数" tabindex="-1">SDL多线程函数 <a class="header-anchor" href="#sdl多线程函数" aria-label="Permalink to &quot;SDL多线程函数&quot;">​</a></h5><p>SDL_CreateThread()：创建一个线程</p><p>SDL_LockMutex(), SDL_UnlockMutex()：互斥量操作</p><h5 id="sdl多线程数据结构" tabindex="-1">SDL多线程数据结构 <a class="header-anchor" href="#sdl多线程数据结构" aria-label="Permalink to &quot;SDL多线程数据结构&quot;">​</a></h5><p>SDL_Thread：线程的句柄</p><h4 id="sdl事件" tabindex="-1">SDL事件 <a class="header-anchor" href="#sdl事件" aria-label="Permalink to &quot;SDL事件&quot;">​</a></h4><h5 id="sdl事件函数" tabindex="-1">SDL事件函数 <a class="header-anchor" href="#sdl事件函数" aria-label="Permalink to &quot;SDL事件函数&quot;">​</a></h5><p>SDL_WaitEvent()：等待一个事件</p><p>SDL_PushEvent()：发送一个事件</p><p>SDL_PumpEvents()：将硬件设备产生的事件放入事件队列</p><p>SDL_PeepEvents()：从事件队列提取一个事件</p><h5 id="sdl事件数据结构" tabindex="-1">SDL事件数据结构 <a class="header-anchor" href="#sdl事件数据结构" aria-label="Permalink to &quot;SDL事件数据结构&quot;">​</a></h5><p>SDL_Event：代表一个事件</p><h4 id="播放器框架" tabindex="-1">播放器框架 <a class="header-anchor" href="#播放器框架" aria-label="Permalink to &quot;播放器框架&quot;">​</a></h4><p><img src="'+u+'" alt="image-20230811165808130"></p><p>问题：</p><p>（1）从av_read_frame读取到一个AVPacket后怎么放入队列？</p><p>（2）从avcodec_recevice_frame读取到一个AVFrame后又怎么放入队列？</p><h3 id="ffmpeg内存模型" tabindex="-1">FFmpeg内存模型 <a class="header-anchor" href="#ffmpeg内存模型" aria-label="Permalink to &quot;FFmpeg内存模型&quot;">​</a></h3><p>从现有的Packet拷贝一个新Packet的时候，有两种情况：</p><ul><li>①两个Packet的buf引用的是同一数据缓存空间，这时候要注意数据缓存空间的释放问题；</li><li>②两个Packet的buf引用不同的数据缓存空间，每个Packet都有数据缓存空间的copy；</li></ul><p><img src="'+_+'" alt="image-20230811165903998"></p><p>avpacket1 = av_packet_alloc();</p><p>avpacket2 = av_packet_alloc();</p><p><img src="'+f+'" alt="image-20230811165918734"></p><p>av_read_frame(, avpacket1)</p><p>内存模型</p><p><img src="'+g+'" alt="image-20230811165944007"></p><p>更为精确的模型</p><p><img src="'+b+'" alt="image-20230811170006101"></p><p>数据共享</p><p>实际共同持有的是AVBuffer</p><p><img src="'+F+'" alt="image-20230811170030076"></p><p>对于多个AVPacket共享同一个缓存空间，FFmpeg使用的引用计数的机制（reference-count）：</p><ul><li>初始化引用计数为1;</li><li>当有新的Packet引用共享的缓存空间时，就将引用计数+1；</li><li>当释放了引用共享空间的Packet，就将引用计数-1；引用计数为0时，就释放掉引用的缓存空间。</li></ul><p>AVFrame也是采用同样的机制。</p><h4 id="avpacket常用api" tabindex="-1">AVPacket常用API <a class="header-anchor" href="#avpacket常用api" aria-label="Permalink to &quot;AVPacket常用API&quot;">​</a></h4><table><thead><tr><th><strong>函数原型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td>AVPacket *av_packet_alloc(void);</td><td>分配AVPacket</td></tr><tr><td>void av_packet_free(AVPacket **pkt);</td><td>释放AVPacket</td></tr><tr><td>void av_init_packet(AVPacket *pkt);</td><td>初始化AVPacket</td></tr><tr><td>int av_new_packet(AVPacket *pkt, int size);</td><td>给AVPacket的buf分配内存，引用计数初始化为1</td></tr><tr><td>int av_packet_ref(AVPacket <em>dst, const AVPacket</em>src);</td><td>增加引用计数</td></tr><tr><td>void av_packet_unref(AVPacket *pkt);</td><td>减少引用计数</td></tr><tr><td>void av_packet_move_ref(AVPacket <em>dst, AVPacket</em>src);</td><td>转移引用计数</td></tr><tr><td>AVPacket <em>av_packet_clone(const AVPacket</em>src);</td><td>等于av_packet_alloc()+av_packet_ref()</td></tr></tbody></table><p>具体见代码：03-avpacket-avframe-api-test</p><h4 id="avframe常用api" tabindex="-1">AVFrame常用API <a class="header-anchor" href="#avframe常用api" aria-label="Permalink to &quot;AVFrame常用API&quot;">​</a></h4><table><thead><tr><th><strong>函数原型</strong></th><th><strong>说明</strong></th></tr></thead><tbody><tr><td>AVFrame *av_frame_alloc(void);</td><td>分配AVFrame</td></tr><tr><td>void av_frame_free(AVFrame **frame);</td><td>释放AVFrame</td></tr><tr><td>int av_frame_ref(AVFrame <em>dst, const AVFrame</em>src);</td><td>增加引用计数</td></tr><tr><td>void av_frame_unref(AVFrame *frame);</td><td>减少引用计数</td></tr><tr><td>void av_frame_move_ref(AVFrame <em>dst, AVFrame</em>src);</td><td>转移引用计数</td></tr><tr><td>int av_frame_get_buffer(AVFrame *frame, int align);</td><td>根据AVFrame分配内存</td></tr><tr><td>AVFrame <em>av_frame_clone(const AVFrame</em>src);</td><td>等于av_frame_alloc()+av_frame_ref()</td></tr></tbody></table><p>具体见代码：avpacket-avframe-api-test</p><p>AVFormat</p><ul><li>封装格式处理模块</li></ul><p>AVFormatContext</p><ul><li>描述了媒体文件的构成及基本信息，是统领全局的基本结构体，贯穿程序始终，很多函数都要用它作为参数，格式转换过程中实现输入和输出功能、保存相关数据的主要结构，描述了一个媒体文件或媒体流的构成和基本信息；</li></ul><p>AVCodec</p><ul><li>编解码模块</li></ul><p>AVFilter</p><ul><li>音频、视频、字幕滤镜 <ul><li>语法规则</li><li>相同线性链，用逗号分隔</li><li>不同线性链，用分号分隔</li><li>中括号，为结果命名</li></ul></li></ul><p>swscale</p><ul><li>视频图像转换计算模块</li><li>参数 <ul><li>分辨率</li><li>像素格式</li></ul></li></ul><p>swresample</p><ul><li>音频重采样</li><li>声道布局调整</li></ul><h3 id="播放器模块划分" tabindex="-1">播放器模块划分 <a class="header-anchor" href="#播放器模块划分" aria-label="Permalink to &quot;播放器模块划分&quot;">​</a></h3><p><img src="'+A+'" alt="image-20230811170219299"></p><p>2</p><p><img src="'+v+'" alt="image-20230811170223436"></p><h3 id="播放器线程划分" tabindex="-1">播放器线程划分 <a class="header-anchor" href="#播放器线程划分" aria-label="Permalink to &quot;播放器线程划分&quot;">​</a></h3><p><img src="'+k+'" alt="image-20230811170236820"></p><p>2</p><p><img src="'+V+'" alt="image-20230811170241599"></p><h3 id="播放器设计重点" tabindex="-1">播放器设计重点 <a class="header-anchor" href="#播放器设计重点" aria-label="Permalink to &quot;播放器设计重点&quot;">​</a></h3><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">bilibli</span><span style="color:#98C379;"> ijkplayer</span><span style="color:#98C379;">  ：</span><span style="color:#98C379;"> ffplay</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>线程的划分</p><ul><li>数据读取线程</li><li>音频解码</li><li>视频解码</li><li>音频播放</li><li>视频播放</li><li>控制响应（播放/暂停/快进/快退等）</li></ul><p>缓存队列的设计</p><ul><li>线程安全</li><li>缓存数据大小</li><li>缓存帧数</li><li>进队列/出队列等</li></ul><p>时钟同步</p><ul><li>音频同步</li><li>视频同步</li><li>外部时钟同步</li><li>时钟序列切换</li></ul><p>音频处理</p><ul><li>音量调节</li><li>重采样</li></ul><p>视频处理</p><ul><li>图像格式转换YUV-&gt;RGB等</li><li>图像缩放1280<em>720-&gt;800</em>480等</li></ul><p>播放器控制</p><ul><li>播放/暂停/停止</li><li>快进/快退/逐帧</li><li>变速播放ffplay没有提供</li></ul><h3 id="ffplay框架架构" tabindex="-1">ffplay框架架构 <a class="header-anchor" href="#ffplay框架架构" aria-label="Permalink to &quot;ffplay框架架构&quot;">​</a></h3><p><img src="'+C+'" alt="image-20230811170624935"></p><h3 id="需要解决的问题" tabindex="-1">需要解决的问题 <a class="header-anchor" href="#需要解决的问题" aria-label="Permalink to &quot;需要解决的问题&quot;">​</a></h3><ul><li>Packet队列</li><li>Frame队列 难点在于视频输出</li><li>Audio输出Video输出</li><li>Decode逻辑</li><li>音视频同步(AVsync)逻辑</li></ul><h3 id="videostate结构体分析" tabindex="-1">VideoState结构体分析 <a class="header-anchor" href="#videostate结构体分析" aria-label="Permalink to &quot;VideoState结构体分析&quot;">​</a></h3><p>AVInputFormat *iformat：容器，比如用来打开mp4/flv等</p><p>AVFormatContext *ic：容器上下文Clock audclk 音频时钟</p><p><strong>FrameQueue sampq;</strong>：解码音频的采样队列</p><p>Decoder auddec：音频解码器</p><p>double audio_clock：当前音频帧的PTS+当前帧Duration</p><p>PacketQueue audioq：解码前的音频队列</p><p>AVStream *audio_st：指向音频媒体流</p><p>这里主要是举例了音频流，视频媒体流也有类似的变量</p><h3 id="ffplay播放器分析" tabindex="-1">ffplay播放器分析 <a class="header-anchor" href="#ffplay播放器分析" aria-label="Permalink to &quot;ffplay播放器分析&quot;">​</a></h3><p>ffplay重点需要debug的函数</p><p>打开文件：avformat_open_input()</p><p>队列(解码前)：packet_queue_put()、packet_queue_get()</p><p>查找解码器：avcodec_find_decoder()</p><p>打开解码器：avcodec_open2()</p><p>读取码流：av_read_frame()</p><p>————————————————————</p><p>音视频解码：avcodec_send_packet()、avcodec_receive_frame()</p><p>队列(解码后)：frame_queue_push() frame_queue_peek()</p><p>同步读取：获取当前主时钟：get_master_clock()、运行的时钟：get_clock()、set_clock()</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ol><li>FFmpeg介绍： <a href="https://www.cnblogs.com/renhui/p/6922971.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/renhui/p/6922971.html</a></li><li>FFmpeg特点： <a href="http://www.ffmpeg.org/about.html" target="_blank" rel="noreferrer">http://www.ffmpeg.org/about.html</a></li><li>FFmpeg特点： <a href="https://www.cnblogs.com/sztom/p/11964797.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/sztom/p/11964797.html</a></li><li>FFmpeg每日更新文档： <a href="http://www.ffmpeg.org/documentation.html" target="_blank" rel="noreferrer">http://www.ffmpeg.org/documentation.html</a></li><li>FFmpeg播放视频基本流程： <a href="https://www.cnblogs.com/renhui/p/9508123.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/renhui/p/9508123.html</a></li><li>封装格式(Container Format)的概念： <a href="https://www.cnblogs.com/leisure_chn/p/10506636.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/leisure_chn/p/10506636.html</a></li><li>流(Stream)的概念： <a href="https://www.cnblogs.com/sztom/p/11964797.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/sztom/p/11964797.html</a></li><li>帧(Frame)的概念： <a href="https://www.cnblogs.com/sztom/p/11964797.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/sztom/p/11964797.html</a></li><li>帧(Frame)的概念： <a href="https://zhuanlan.zhihu.com/practice-ffmpeg" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/practice-ffmpeg</a></li><li>编解码(Codec)的概念： <a href="https://www.cnblogs.com/samirchen/archive/2017/06/24/7073102.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/samirchen/archive/2017/06/24/7073102.html</a></li><li>解码(Codec)的概念： <a href="https://www.cnblogs.com/renhui/p/9293057.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/renhui/p/9293057.html</a></li><li>数据包(Packet)的概念： <a href="https://www.cnblogs.com/samirchen/archive/2017/06/24/7073102.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/samirchen/archive/2017/06/24/7073102.html</a></li><li>数据包(Packet)的概念： <a href="https://blog.csdn.net/lsy5631932/article/details/8647134" target="_blank" rel="noreferrer">https://blog.csdn.net/lsy5631932/article/details/8647134</a></li><li><a href="https://blog.csdn.net/leixiaohua1020/article/details/25422685" target="_blank" rel="noreferrer">https://blog.csdn.net/leixiaohua1020/article/details/25422685</a></li><li>转码的概念： <a href="https://www.cnblogs.com/yongfengnice/p/7133714.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/yongfengnice/p/7133714.html</a></li><li><a href="https://blog.csdn.net/leixiaohua1020/article/details/25422685" target="_blank" rel="noreferrer">https://blog.csdn.net/leixiaohua1020/article/details/25422685</a></li><li>转码步骤 <a href="https://www.cnblogs.com/yongfengnice/p/7133714.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/yongfengnice/p/7133714.html</a></li><li>「文件格式(File Format)」与「封装格式(Container Format)」的区别： <a href="https://www.cnblogs.com/leisure_chn/p/10506636.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/leisure_chn/p/10506636.html</a></li><li>FFmpeg封装格式处理文件步骤： <a href="https://www.cnblogs.com/leisure_chn/p/10506636.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/leisure_chn/p/10506636.html</a></li><li>FFmpeg主要封装格式一览表： <a href="https://blog.csdn.net/leixiaohua1020/article/details/18893769" target="_blank" rel="noreferrer">https://blog.csdn.net/leixiaohua1020/article/details/18893769</a></li><li>「封装格式(Container Format)」与「编解码格式(Codec Format)」一览表： <a href="https://www.cnblogs.com/yongfengnice/p/7133714.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/yongfengnice/p/7133714.html</a></li><li>FFmpeg 播放视频基本流程 <a href="https://www.cnblogs.com/renhui/p/9508123.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/renhui/p/9508123.html</a></li><li>ffmpeg模块相关结构： <a href="https://www.cnblogs.com/brucehou/archive/2011/12/20/2295059.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/brucehou/archive/2011/12/20/2295059.html</a></li></ol>',258),y=[P];function x(q,D,E,L,S,B){return l(),a("div",null,y)}const M=e(w,[["render",x]]);export{T as __pageData,M as default};
